:root {
  --card-bg: #ffffff;
  --card-border: #e8e0d8;
  --header-bg: #3d2c1e;
  --tag-bg: #c8602a;
  --tag-text: #ffffff;
  --title-color: #ffffff;
  --desc-color: #c9b8a8;
  --meta-bg: #faf7f4;
  --meta-border: #ece5dc;
  --meta-icon-color: #c8602a;
  --meta-value-color: #2c1e12;
  --meta-label-color: #9a8070;
  --divider-color: #ddd4c8;
  --section-title-color: #3d2c1e;
  --ingredient-dot-color: #c8602a;
  --ingredient-text: #5a4030;
  --btn-bg: #c8602a;
  --btn-text: #ffffff;
  --btn-hover-bg: #a84e20;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.recipe-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 16px;
  width: 300px;
  overflow: hidden;
}

.recipe-header {
  background: var(--header-bg);
  padding: 20px;
}

.cuisine-tag {
  display: inline-block;
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 3px 10px;
  border-radius: 20px;
  margin-bottom: 10px;
}

.recipe-title {
  color: var(--title-color);
  font-size: 20px;
  font-weight: 700;
  margin: 0 0 8px 0;
  line-height: 1.2;
}

.recipe-desc {
  color: var(--desc-color);
  font-size: 13px;
  line-height: 1.5;
  margin: 0;
}

.recipe-meta {
  display: flex;
  align-items: center;
  background: var(--meta-bg);
  border-bottom: 1px solid var(--meta-border);
  padding: 14px 0;
}

.meta-item {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.meta-icon {
  font-size: 16px;
  line-height: 1;
}

.meta-value {
  color: var(--meta-value-color);
  font-size: 15px;
  font-weight: 700;
  line-height: 1.2;
}

.meta-label {
  color: var(--meta-label-color);
  font-size: 11px;
  font-weight: 500;
}

.meta-divider {
  width: 1px;
  height: 36px;
  background: var(--divider-color);
}

.ingredients-section {
  padding: 16px 20px 12px;
}

.section-title {
  color: var(--section-title-color);
  font-size: 13px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  margin: 0 0 10px 0;
}

.ingredient-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.ingredient-item {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--ingredient-text);
  font-size: 13px;
  font-weight: 400;
  line-height: 1.4;
}

.ingredient-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--ingredient-dot-color);
  flex-shrink: 0;
}

.cook-btn {
  display: block;
  width: calc(100% - 40px);
  margin: 4px 20px 20px;
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: 10px;
  padding: 12px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  letter-spacing: 0.03em;
}
